1713 /// Matches instructions with Opcode and three operands.
1714 template <typename T0, typename T1, typename T2, unsigned Opcode,
1715           bool CommutableOp2Op3 = false>
1716 struct ThreeOps_match {
1717   T0 Op1;
1718   T1 Op2;
1719   T2 Op3;
1720 
1721   ThreeOps_match(const T0 &Op1, const T1 &Op2, const T2 &Op3)
1722       : Op1(Op1), Op2(Op2), Op3(Op3) {}
1723 
1724   template <typename OpTy> bool match(OpTy *V) {
1725     if (V->getValueID() == Value::InstructionVal + Opcode) {
1726       auto *I = cast<Instruction>(V);
1727       if (!Op1.match(I->getOperand(0)))
1728         return false;
1729       if (Op2.match(I->getOperand(1)) && Op3.match(I->getOperand(2)))
1730         return true;
1731       return CommutableOp2Op3 && Op2.match(I->getOperand(2)) &&
1732              Op3.match(I->getOperand(1));
