1744     return false;
1745 
1746   auto *C0 = dyn_cast<CastInst>(V0);
1747   auto *C1 = dyn_cast<CastInst>(V1);
1748   if (!C0 || !C1)
1749     return false;
1750 
1751   Instruction::CastOps Opcode = C0->getOpcode();
1752   if (C0->getSrcTy() != C1->getSrcTy())
1753     return false;
1754 
1755   // Handle shuffle(zext_nneg(x), sext(y)) -> sext(shuffle(x,y)) folds.
1756   if (Opcode != C1->getOpcode()) {
1757     if (match(C0, m_SExtLike(m_Value())) && match(C1, m_SExtLike(m_Value())))
1758       Opcode = Instruction::SExt;
1759     else
1760       return false;
1761   }
1762 
1763   auto *ShuffleDstTy = dyn_cast<FixedVectorType>(I.getType());
1764   auto *CastDstTy = dyn_cast<FixedVectorType>(C0->getDestTy());
1765   auto *CastSrcTy = dyn_cast<FixedVectorType>(C0->getSrcTy());
1766   if (!ShuffleDstTy || !CastDstTy || !CastSrcTy)
1767     return false;
1768 
1769   unsigned NumSrcElts = CastSrcTy->getNumElements();
1770   unsigned NumDstElts = CastDstTy->getNumElements();
1771   assert((NumDstElts == NumSrcElts || Opcode == Instruction::BitCast) &&
1772          "Only bitcasts expected to alter src/dst element counts");
1773 
1774   // Check for bitcasting of unscalable vector types.
1775   // e.g. <32 x i40> -> <40 x i32>
1776   if (NumDstElts != NumSrcElts && (NumSrcElts % NumDstElts) != 0 &&
1777       (NumDstElts % NumSrcElts) != 0)
1778     return false;
1779 
1780   SmallVector<int, 16> NewMask;
1781   if (NumSrcElts >= NumDstElts) {
1782     // The bitcast is from wide to narrow/equal elements. The shuffle mask can
1783     // always be expanded to the equivalent form choosing narrower elements.
1784     assert(NumSrcElts % NumDstElts == 0 && "Unexpected shuffle mask");
1785     unsigned ScaleFactor = NumSrcElts / NumDstElts;
1786     narrowShuffleMaskElts(ScaleFactor, OldMask, NewMask);
1787   } else {
1788     // The bitcast is from narrow elements to wide elements. The shuffle mask
1789     // must choose consecutive elements to allow casting first.
1790     assert(NumDstElts % NumSrcElts == 0 && "Unexpected shuffle mask");
1791     unsigned ScaleFactor = NumDstElts / NumSrcElts;
1792     if (!widenShuffleMaskElts(ScaleFactor, OldMask, NewMask))
1793       return false;
1794   }
1795 
1796   auto *NewShuffleDstTy =
1797       FixedVectorType::get(CastSrcTy->getScalarType(), NewMask.size());
1798 
1799   // Try to replace a castop with a shuffle if the shuffle is not costly.
1800   InstructionCost CostC0 =
1801       TTI.getCastInstrCost(C0->getOpcode(), CastDstTy, CastSrcTy,
1802                            TTI::CastContextHint::None, CostKind);
1803   InstructionCost CostC1 =
1804       TTI.getCastInstrCost(C1->getOpcode(), CastDstTy, CastSrcTy,
1805                            TTI::CastContextHint::None, CostKind);
1806   InstructionCost OldCost = CostC0 + CostC1;
1807   OldCost +=
1808       TTI.getShuffleCost(TargetTransformInfo::SK_PermuteTwoSrc, CastDstTy,
1809                          OldMask, CostKind, 0, nullptr, {}, &I);
1810 
1811   InstructionCost NewCost = TTI.getShuffleCost(
1812       TargetTransformInfo::SK_PermuteTwoSrc, CastSrcTy, NewMask, CostKind);
1813   NewCost += TTI.getCastInstrCost(Opcode, ShuffleDstTy, NewShuffleDstTy,
1814                                   TTI::CastContextHint::None, CostKind);
1815   if (!C0->hasOneUse())
1816     NewCost += CostC0;
1817   if (!C1->hasOneUse())
1818     NewCost += CostC1;
1819 
1820   LLVM_DEBUG(dbgs() << "Found a shuffle feeding two casts: " << I
1821                     << "\n  OldCost: " << OldCost << " vs NewCost: " << NewCost
1822                     << "\n");
1823   if (NewCost > OldCost)
1824     return false;
1825 
1826   Value *Shuf = Builder.CreateShuffleVector(C0->getOperand(0),
1827                                             C1->getOperand(0), NewMask);
1828   Value *Cast = Builder.CreateCast(Opcode, Shuf, ShuffleDstTy);
1829 
1830   // Intersect flags from the old casts.
1831   if (auto *NewInst = dyn_cast<Instruction>(Cast)) {
1832     NewInst->copyIRFlags(C0);
1833     NewInst->andIRFlags(C1);
1834   }
1835 
1836   Worklist.pushValue(Shuf);
1837   replaceValue(I, *Cast);
1838   return true;
